const $ = (id) => root.querySelector('#' + id);
// 30 portrait-photography styles. Each value is a descriptive PHOTOGRAPHIC look
// (lighting + lens + mood) so every result is a realistic photo portrait.
const STYLES = {
  'Classic Studio Headshot': 'a clean professional studio headshot, soft key light with subtle fill, neutral seamless backdrop, tack-sharp eyes, 85mm lens look',
  'Rembrandt Lighting': 'dramatic Rembrandt lighting with a triangle of light on the cheek, deep shadows, chiaroscuro, dark background',
  'Butterfly Glamour Light': 'glamour beauty lighting (butterfly/paramount), symmetrical soft light from above, flawless skin, bright catchlights in the eyes',
  'Fine-Art Black & White': 'a high-contrast fine-art black-and-white portrait, rich tonal range, timeless, exquisite detail',
  'Golden Hour Natural Light': 'warm golden-hour backlight, soft rim light on the hair, dreamy bokeh, natural outdoor light',
  'Editorial Fashion (Vogue)': 'a high-fashion editorial magazine portrait, striking confident pose, polished lighting, glossy and bold',
  'Cinematic Film Still': 'a cinematic film-still portrait, anamorphic shallow depth of field, moody teal-and-orange color grade',
  'Film Noir': 'a film-noir portrait, hard directional light, venetian-blind shadows, dramatic black and white, mysterious',
  'Environmental Portrait': 'an environmental portrait showing the subject in a real setting, natural light, storytelling context',
  'Corporate Headshot': 'a polished modern corporate headshot, confident and approachable, soft even lighting, clean neutral background',
  'Vintage 35mm Film': 'a warm vintage 35mm film portrait, soft grain, gently faded colors, nostalgic Kodak Portra look',
  'High-Key Bright': 'a bright high-key portrait, white background, soft near-shadowless light, airy and clean',
  'Low-Key Moody': 'a low-key moody portrait, a single light source, deep blacks, intimate and dramatic',
  'Beauty Close-Up': 'a tight beauty close-up lit with a beauty dish, crisp catchlights, detailed natural skin texture',
  'Documentary / Photojournalism': 'a candid documentary portrait in available light, authentic and unposed, honest realism',
  'Street Portrait': 'a candid street portrait, natural city light, soft urban background bokeh, spontaneous and real',
  'Old-Master Painterly Photo': 'an old-master-inspired photographic portrait with classical lighting and palette — but a real photograph, not a painting',
  'Soft Pastel': 'a soft pastel portrait, gentle diffused light, light airy color palette, delicate and elegant',
  'Dramatic Rim Light': 'a dramatic rim-light portrait, strong backlight outlining the silhouette, dark background, bold',
  'Warm Lifestyle': 'a warm tender lifestyle portrait, soft window light, gentle and emotional, natural tones',
  'Athletic / Sports': 'a dynamic athletic portrait, hard dramatic light, energetic and powerful, fine detail',
  'Neon Nightlife': 'a neon-lit night portrait, colorful neon reflections, cinematic moody urban glow',
  'Overcast Soft Daylight': 'a soft overcast-daylight portrait, even flattering light, natural skin tones, relaxed',
  'Window Light Indoor': 'a classic window-light indoor portrait, soft directional daylight, gentle falloff, intimate',
  'Hollywood Glamour (1940s)': 'a classic 1940s Hollywood glamour portrait, glossy black and white, dramatic spotlight, elegant retro',
  'Polaroid / Instant Film': 'an instant-film polaroid portrait, soft focus, vintage instant tones, candid and personal',
  'Startup Founder Editorial': 'a modern editorial founder portrait, clean confident lighting, contemporary, slightly desaturated',
  'Travel Portrait': 'a vivid travel portrait in natural light, rich location color, documentary travel-magazine feel',
  'Fitness Studio': 'a sculpted fitness portrait, dramatic side light defining form, dark studio, high contrast',
  'Romantic Wedding': 'a romantic soft-focus wedding portrait, warm dreamy backlight, elegant and emotional'
};
const sel = $('style');
Object.keys(STYLES).forEach(function (k) { const o = document.createElement('option'); o.value = k; o.textContent = k; sel.appendChild(o); });

let ratio = '';
const seg = $('ratioSeg');
seg.querySelectorAll('.seg-btn').forEach(function (b) {
  b.addEventListener('click', function () {
    seg.querySelectorAll('.seg-btn').forEach(function (x) { x.classList.remove('active'); });
    b.classList.add('active'); ratio = b.getAttribute('data-r') || '';
  });
});

let photo = null;
$('pick').addEventListener('click', function () { $('file').click(); });
$('file').addEventListener('change', function () {
  const f = $('file').files[0]; if (!f) return;
  const r = new FileReader();
  r.onload = function () { photo = r.result; $('src').src = photo; $('srcWrap').style.display = 'block'; $('fname').textContent = f.name; $('go').disabled = false; };
  r.readAsDataURL(f);
});

async function generate() {
  if (!photo) { $('status').textContent = 'Upload a photo first.'; return; }
  const extra = $('extra').value.trim();
  const prompt = 'A photorealistic portrait PHOTOGRAPH of this person in the style of ' + STYLES[sel.value] + ". Preserve the person's identity, facial features, proportions and likeness — it must clearly be the same person. Real photography: natural realistic skin and lighting, sharp focus, professional quality." + (extra ? ' ' + extra + '.' : '') + ' Photographic, not an illustration or painting. No text, no watermark.';
  const go = $('go'); go.disabled = true; $('status').textContent = 'Generating your portrait…';
  try {
    const opts = { prompt: prompt, inputImage: photo };
    if (ratio) opts.aspect = ratio;
    const out = await bridge.image(opts);
    $('out').src = out; $('outWrap').style.display = 'block'; $('actions').style.display = 'flex'; $('status').textContent = '';
  } catch (e) { $('status').textContent = 'Error: ' + ((e && e.message) || 'generation failed'); }
  go.disabled = false;
}
$('go').addEventListener('click', generate);
$('regen').addEventListener('click', generate);
$('dl').addEventListener('click', function () { if ($('out').getAttribute('src')) api.download('portrait.png', $('out').src); });
